import { VitalGauge } from 'ui/containers/performance/components/VitalGauge';
import { WebVitalsDisplay } from 'ui/containers/performance/components/WebVitalsDisplay';
import { BundleSizeTreemap } from 'ui/containers/performance/components/BundleSizeTreemap';

function PerformanceDashboard() {
  return (
    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
      <VitalGauge name="LCP" value={2200} rating="needs-improvement" unit="ms" thresholds={{ good: 2500, poor: 4000 }} />
      <WebVitalsDisplay vitals={{ lcp: 2200, fcp: 1500, cls: 0.05, ttfb: 600 }} />
      <BundleSizeTreemap modules={modules} totalSize={500000} gzippedSize={150000} />
    </div>
  );
}

import { AxeAuditPanel } from 'ui/containers/accessibility/components/AxeAuditPanel';
import { ContrastChecker } from 'ui/containers/accessibility/components/ContrastChecker';

function AccessibilityAudit() {
  return (
    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
      <AxeAuditPanel />
      <ContrastChecker />
    </div>
  );
}

import { CodeComparisonViewer } from 'ui/containers/case-studies/components/CodeComparisonViewer';

function CodeReview() {
  return <CodeComparisonViewer comparisons={comparisons} />;
}
